const { CosmosClient } = require("@azure/cosmos");

const DEFAULT_BATCH_SIZE = parseInt(process.env.BATCH_SIZE || "250", 10);
const DEFAULT_MAX_ITEMS = parseInt(process.env.MAX_ITEMS || "50000", 10);
const SAFETY_STOP_MS = 9 * 60 * 1000 + 15 * 1000;

let cachedClient;
let cachedContainer;

function getContainer() {
  if (cachedContainer) return cachedContainer;

  const endpoint = process.env.COSMOS_ENDPOINT;
  const key = process.env.COSMOS_KEY;
  const databaseId = process.env.COSMOS_DATABASE_ID;
  const containerId = process.env.COSMOS_CONTAINER_ID;

  if (!endpoint || !key || !databaseId || !containerId) {
    throw new Error("Missing Cosmos DB configuration.");
  }

  cachedClient = cachedClient || new CosmosClient({
    endpoint,
    key,
    connectionPolicy: {
      enableEndpointDiscovery: true
    }
  });

  cachedContainer = cachedClient.database(databaseId).container(containerId);
  return cachedContainer;
}

function now() {
  return Date.now();
}

function parsePositiveInt(value, fallback) {
  const n = parseInt(value, 10);
  return Number.isFinite(n) && n > 0 ? n : fallback;
}

function shouldStop(startTime, processedCount, maxItems) {
  if (processedCount >= maxItems) return true;
  return now() - startTime >= SAFETY_STOP_MS;
}

async function processDocument(doc, context) {
  return {
    id: doc.id,
    processedAt: new Date().toISOString()
  };
}

module.exports = async function (context, req) {
  const startTime = now();

  context.log("Batch processing started.");

  try {
    const container = getContainer();

    const batchSize = parsePositiveInt(
      req?.query?.batchSize || req?.body?.batchSize || process.env.BATCH_SIZE,
      DEFAULT_BATCH_SIZE
    );

    const maxItems = parsePositiveInt(
      req?.query?.maxItems || req?.body?.maxItems || process.env.MAX_ITEMS,
      DEFAULT_MAX_ITEMS
    );

    const partitionKey = req?.query?.partitionKey ?? req?.body?.partitionKey;
    const continuationToken =
      req?.query?.continuationToken ??
      req?.body?.continuationToken ??
      null;

    const queryText =
      req?.body?.query ||
      req?.query?.query ||
      "SELECT * FROM c";

    const querySpec = {
      query: queryText
    };

    const options = {
      maxItemCount: batchSize,
      continuationToken
    };

    if (partitionKey !== undefined) {
      options.partitionKey = partitionKey;
    }

    let processedCount = 0;
    let pages = 0;
    let nextContinuationToken = continuationToken;
    const results = [];

    while (!shouldStop(startTime, processedCount, maxItems)) {
      const iterator = container.items.query(querySpec, {
        ...options,
        continuationToken: nextContinuationToken,
        maxItemCount: Math.min(batchSize, maxItems - processedCount)
      });

      const { resources, continuationToken: newContinuationToken } = await iterator.fetchNext();

      pages += 1;

      if (!resources || resources.length === 0) {
        nextContinuationToken = null;
        break;
      }

      for (const doc of resources) {
        if (shouldStop(startTime, processedCount, maxItems)) {
          break;
        }

        const processed = await processDocument(doc, context);
        results.push(processed);
        processedCount += 1;
      }

      nextContinuationToken = newContinuationToken || null;

      if (!nextContinuationToken) {
        break;
      }
    }

    const completed = !nextContinuationToken && processedCount < maxItems
      ? true
      : !nextContinuationToken;

    context.log("Batch processing finished.", {
      processedCount,
      pages,
      completed,
      hasContinuation: !!nextContinuationToken
    });

    context.res = {
      status: 200,
      headers: {
        "Content-Type": "application/json"
      },
      body: {
        success: true,
        completed,
        processedCount,
        pages,
        continuationToken: nextContinuationToken,
        timeoutConfigured: "00:10:00",
        note: "On Azure Functions Consumption plan, execution timeout cannot exceed 10 minutes. This function uses the maximum timeout and stops safely before forced termination to allow continuation.",
        results
      }
    };
  } catch (error) {
    context.log.error("Batch processing failed.", error);

    context.res = {
      status: 500,
      headers: {
        "Content-Type": "application/json"
      },
      body: {
        success: false,
        error: error.message
      }
    };
  }
};